    showtime = next((s for s in showtimes if s.get('showtime_id') == showtime_id), None)
    if showtime is None:
        return "Showtime not found", 404

    movies = load_movies()
    movie = next((m for m in movies if int(m.get('movie_id')) == showtime.get('movie_id')), None)

    seats = load_seats()

    # We assume theater_id and screen_id from showtime and seats
    # Filter seats for that theater and screen
    theater_id = showtime.get('theater_id')
    # We don't have screen_id in showtime.txt based on schema, so we must match theater_id only
    seats_for_showtime = [seat for seat in seats if seat.get('theater_id') == theater_id]

    # Prepare seat map grouped by row
    seat_map = {}
    for seat in seats_for_showtime:
        row = seat.get('row')
        seat_map.setdefault(row, []).append(seat)

    # Sort seats in each row by column
    for row in seat_map:
        seat_map[row].sort(key=lambda x: x.get('column'))

    return render_template('seat_selection.html',
                           seat_map=seat_map,
                           movie_title=movie.get('title') if movie else 'Unknown',
                           showtime_date=showtime.get('showtime_date'),
                           showtime_time=showtime.get('showtime_time'),
