from flask import Flask, render_template, request, redirect, url_for
import os
from datetime import date

app = Flask(__name__)

# Data loading functions

def load_movies():
    movies = []
    filepath = 'data/movies.txt'
    if not os.path.exists(filepath):
        return movies
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            lines = f.read().splitlines()
            if lines:
                header = lines[0].split('|')
                for line in lines[1:]:
                    fields = line.split('|')
                    if len(fields) == len(header):
                        movie = dict(zip(header, fields))
                        try:
                            movie['rating'] = float(movie['rating']) if movie['rating'] else None
                        except:
                            movie['rating'] = None
                        try:
                            movie['duration'] = int(movie['duration']) if movie['duration'] else None
                        except:
                            movie['duration'] = None
                        movies.append(movie)
    except IOError:
        pass
    return movies


def load_theaters():
    theaters = []
    filepath = 'data/theaters.txt'
    if not os.path.exists(filepath):
        return theaters
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            lines = f.read().splitlines()
            if lines:
                header = lines[0].split('|')
                for line in lines[1:]:
                    fields = line.split('|')
                    if len(fields) == len(header):
                        theater = dict(zip(header, fields))
                        try:
                            theater['screens'] = int(theater['screens']) if theater['screens'] else None
                        except:
                            theater['screens'] = None
                        if 'facilities' in theater and theater['facilities']:
                            theater['facilities'] = [f.strip() for f in theater['facilities'].split(',')]
                        else:
                            theater['facilities'] = []
                        theaters.append(theater)
    except IOError:
        pass
    return theaters


def load_showtimes():
    showtimes = []
    filepath = 'data/showtimes.txt'
    if not os.path.exists(filepath):
        return showtimes
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            lines = f.read().splitlines()
            if lines:
                header = lines[0].split('|')
                for line in lines[1:]:
                    fields = line.split('|')
                    if len(fields) == len(header):
                        showtime = dict(zip(header, fields))
                        try:
                            showtime['showtime_id'] = int(showtime['showtime_id'])
                            showtime['movie_id'] = int(showtime['movie_id'])
                            showtime['theater_id'] = int(showtime['theater_id'])
                            showtime['price'] = float(showtime['price'])
                            showtime['available_seats'] = int(showtime['available_seats'])
                        except:
                            pass
