            if lines:
                header = lines[0].split('|')
                for line in lines[1:]:
                    fields = line.split('|')
                    if len(fields) == len(header):
                        seat = dict(zip(header, fields))
                        try:
                            seat['seat_id'] = int(seat['seat_id'])
                            seat['theater_id'] = int(seat['theater_id'])
                            seat['screen_id'] = int(seat['screen_id'])
                            seat['column'] = int(seat['column'])
                        except:
                            pass
                        seats.append(seat)
    except IOError:
        pass
    return seats


def load_bookings():
    bookings = []
    filepath = 'data/bookings.txt'
    if not os.path.exists(filepath):
        return bookings
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            lines = f.read().splitlines()
            for line in lines:
                fields = line.strip().split('|')
                # Format: booking_id|showtime_id|customer_name|customer_email|booking_date|total_price|status|seats_booked
                if len(fields) == 8:
                    booking_id, showtime_id, customer_name, customer_email, booking_date, total_price, status, seats_booked_str = fields
                    try:
                        booking_id = int(booking_id)
                        showtime_id = int(showtime_id)
                        total_price = float(total_price)
                        seats_booked = [s.strip() for s in seats_booked_str.split(',') if s.strip()]
                    except Exception:
                        seats_booked = []
                    booking = {
                        'booking_id': booking_id,
                        'showtime_id': showtime_id,
                        'customer_name': customer_name,
                        'customer_email': customer_email,
                        'booking_date': booking_date,
                        'total_price': total_price,
                        'status': status,
                        'seats_booked': seats_booked
