    if movie is None:
        return "Movie not found", 404

    showtimes = load_showtimes()
    theaters = load_theaters()

    # Filter showtimes for movie
    filtered_showtimes = [s for s in showtimes if s['movie_id'] == movie_id]

    # Apply theater filter and date filter
    theaters_dict = {t['theater_id']: t for t in theaters}

    theater_filter = None
    date_filter = None
    if request.method == 'POST':
        theater_filter = request.form.get('theater_filter')
        date_filter = request.form.get('date_filter')
