            try:
                theater_filter = int(theater_filter)
            except:
                theater_filter = None

    showtimes_filtered = []
    for st in filtered_showtimes:
        # Filter by theater
        if theater_filter and st['theater_id'] != theater_filter:
            continue
        # Filter by date
